{"version":3,"sources":["../../../src/utils/dir.ts"],"sourcesContent":["import fs from 'fs-extra';\n\nexport function directoryExistsSync(file: string): boolean {\n  try {\n    return fs.statSync(file)?.isDirectory() ?? false;\n  } catch {\n    return false;\n  }\n}\n\nexport async function directoryExistsAsync(file: string): Promise<boolean> {\n  return (await fs.promises.stat(file).catch(() => null))?.isDirectory() ?? false;\n}\n\nexport async function fileExistsAsync(file: string): Promise<boolean> {\n  return (await fs.promises.stat(file).catch(() => null))?.isFile() ?? false;\n}\n\nexport const ensureDirectoryAsync = (path: string) => fs.promises.mkdir(path, { recursive: true });\n\nexport const ensureDirectory = (path: string) => fs.mkdirSync(path, { recursive: true });\n\nexport const copySync = fs.copySync;\n\nexport const copyAsync = fs.copy;\n\nexport const removeAsync = fs.remove;\n"],"names":["directoryExistsSync","directoryExistsAsync","fileExistsAsync","file","fs","statSync","isDirectory","promises","stat","catch","isFile","ensureDirectoryAsync","path","mkdir","recursive","ensureDirectory","mkdirSync","copySync","copyAsync","copy","removeAsync","remove"],"mappings":"AAAA;;;;QAEgBA,mBAAmB,GAAnBA,mBAAmB;QAQbC,oBAAoB,GAApBA,oBAAoB;QAIpBC,eAAe,GAAfA,eAAe;;AAdtB,IAAA,QAAU,kCAAV,UAAU,EAAA;;;;;;AAElB,SAASF,mBAAmB,CAACG,IAAY,EAAW;IACzD,IAAI;YACKC,GAAiB;YAAjBA,IAAgC;QAAvC,OAAOA,CAAAA,IAAgC,GAAhCA,CAAAA,GAAiB,GAAjBA,QAAE,QAAA,CAACC,QAAQ,CAACF,IAAI,CAAC,SAAa,GAA9BC,KAAAA,CAA8B,GAA9BA,GAAiB,CAAEE,WAAW,EAAE,YAAhCF,IAAgC,GAAI,KAAK,CAAC;KAClD,CAAC,OAAM;QACN,OAAO,KAAK,CAAC;KACd;CACF;AAEM,eAAeH,oBAAoB,CAACE,IAAY,EAAoB;QAClE,GAAgD;QAAhD,IAA+D;IAAtE,OAAO,CAAA,IAA+D,GAA/D,CAAA,GAAgD,GAA/C,MAAMC,QAAE,QAAA,CAACG,QAAQ,CAACC,IAAI,CAACL,IAAI,CAAC,CAACM,KAAK,CAAC,IAAM,IAAI;IAAA,CAAC,SAAc,GAA7D,KAAA,CAA6D,GAA7D,GAAgD,CAAEH,WAAW,EAAE,YAA/D,IAA+D,GAAI,KAAK,CAAC;CACjF;AAEM,eAAeJ,eAAe,CAACC,IAAY,EAAoB;QAC7D,GAAgD;QAAhD,IAA0D;IAAjE,OAAO,CAAA,IAA0D,GAA1D,CAAA,GAAgD,GAA/C,MAAMC,QAAE,QA